const body = $input.first().json.body;

return [{
  json: {
    messages: [
      {
        role: 'system',
        content: 'You are an insurance claims triage specialist. Analyze the claim and respond ONLY with a raw JSON object (no markdown, no backticks).\n\nPriority rules — follow strictly:\n- High: life-threatening injuries, hospitalization, major fire or flood, total vehicle loss, crime in progress\n- Medium: moderate property damage, non-urgent medical, theft, partial vehicle damage\n- Low: minor scratches or dents, travel delays, lost items, small claims under $500\n\nRequired fields: priority (High/Medium/Low), required_documents (array of strings), estimated_processing_days (number: High=1, Medium=5, Low=10), summary (1-2 sentences), next_steps (string)'
      },
      {
        role: 'user',
        content: 'Analyze this insurance claim. Type: ' + (body.claim_type || 'unknown') + '. Date: ' + (body.incident_date || 'unknown') + '. Description: ' + (body.description || 'No description provided')
      }
    ],
    max_tokens: 500,
    temperature: 0.2
  }
}];

const raw = $input.first().json.choices[0].message.content;

let result;
try {
  result = JSON.parse(raw.replace(/```json|```/g, '').trim());
} catch(e) {
  result = {
    priority: 'Medium',
    required_documents: ['Proof of identity', 'Incident report'],
    estimated_processing_days: 5,
    summary: 'Claim received. Manual review required.',
    next_steps: 'A claims officer will contact you within 2 business days.'
  };
}

const slaMap = {
  'High': 'URGENT - Senior officer assigned. Resolution within 24 hours.',
  'Medium': 'Standard queue. Resolution within 3-5 business days.',
  'Low': 'Self-service queue. Please submit documents via the portal.'
};

result.sla = slaMap[result.priority] || slaMap['Medium'];

return [{ json: result }];
